  mutable arangodb::basics::ReadWriteLock _jwtSecretLock;

  std::vector<std::string> _jwtPassiveSecrets;
  std::string _jwtActiveSecret;
  bool _jwtActiveSecretIsES256{false};  /// true if active secret is ES256 key
